section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/qa-rc-smoke-pack-template.json",
  "type": "object",
  "title": "QA Release Candidate Smoke Pack",
  "required": [
    "pack_id",
    "pack_version",
    "steps",
    "max_wall_clock_seconds",
    "critical_paths_covered",
    "last_reviewed",
    "waiver_policy"
  ],
  "additionalProperties": false,
  "properties": {
    "pack_id": {
      "type": "string",
      "minLength": 1,
      "description": "Pack identifier."
    },
    "pack_version": {
      "type": "string",
      "minLength": 1,
      "description": "Semver."
    },
    "steps": {
      "type": "array",
      "items": {
        "type": "object"
      },
      "description": "List of {n, name, command, expected, critical_path}."
    },
    "max_wall_clock_seconds": {
      "type": "integer",
      "description": "Hard cap; \u2264300."
    },
    "critical_paths_covered": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Must include auth, payment, write, read, export."
    },
    "last_reviewed": {
      "type": "string",
      "minLength": 1,
      "description": "ISO date."
    },
    "waiver_policy": {
      "type": "string",
      "minLength": 1,
      "description": "Who can waive a failed step."
    }
  }
}
